/// Which MFX effect type "owns" a given byte of the MFX block, if any.
/// `None` for common bytes (the 7 always-present header bytes at page
/// 0x03 offsets 0x00..=0x06) and for any byte FloorBoard left undocumented.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum MfxTypeOwner {
    Equalizer,
    SuperFilter,
    Phaser,
    StepPhaser,
    RingModulator,
    Tremolo,
    AutoPan,
    Slicer,
    VkRotary,
    HexaChorus,
    SpaceD,
    Flanger,
    StepFlanger,
    GuitarAmpSim,
    Compressor,
    Limiter,
    ThreeTapPanDelay,
    TimeCtrlDelay,
    LofiCompressor,
    PitchShifter,
}

/// One byte of the MFX parameter block.
#[derive(Debug, Clone, Copy)]
pub struct MfxParamEntry {
    /// Wire page byte (0x03 or 0x04).
    pub page: u8,
    /// Offset within the page (0x00..=0x7F).
    pub offset: u8,
    /// Effect type that this byte parameterises, or None for the common
    /// always-present header bytes.
    pub owning_type: Option<MfxTypeOwner>,
    /// Human-readable parameter name (e.g. "Equalizer Low Freq").
    pub name: &'static str,
    /// Named byte values for this param. Empty for purely numeric
    /// (range-only) parameters.
    pub values: &'static [(u8, &'static str)],
    /// Raw wire-byte range (min, max). None for purely enumerated
    /// parameters.
    pub range: Option<(u8, u8)>,
    /// Display range (min, max) for numeric parameters whose
    /// display values differ from their wire bytes (e.g. -15..=+15
    /// dB across wire 0x00..=0x1E).
    pub display_range: Option<(i32, i32)>,
    /// Tooltip-friendly description from the owner's manual
    /// (hand-curated, keyed by parameter name).
    pub help: &'static str,
}

/// Linear MFX block size — bytes at page 0x03 0x00..=0x7F (= 0..=127)
/// followed by page 0x04 0x00..=0x7F (= 128..=255).
pub const MFX_BLOCK_SIZE: usize = 256;

